-- =============================================
-- Z2 DATA EXPORT - 2026-03-22
-- Importar con: psql -U <user> -d <db> -f export_2026-03-22.sql
-- =============================================

SET session_replication_role = replica; -- deshabilita FK checks temporalmente

-- Eliminar datos existentes
TRUNCATE TABLE taxes, expenses, project_hours, project_owners, projects, client_referentes, collaborators, clients RESTART IDENTITY CASCADE;

-- clients (2 registros)

-- client_referentes (1 registros)

-- collaborators (5 registros)

-- projects (28 registros)

-- project_owners (28 registros)

-- project_hours: sin datos

-- expenses (19 registros)

-- taxes: sin datos


-- Resetear sequences al valor maximo de cada tabla
SELECT setval('clients_id_seq', COALESCE((SELECT MAX(id) FROM clients), 1));
SELECT setval('client_referentes_id_seq', COALESCE((SELECT MAX(id) FROM client_referentes), 1));
SELECT setval('collaborators_id_seq', COALESCE((SELECT MAX(id) FROM collaborators), 1));
SELECT setval('projects_id_seq', COALESCE((SELECT MAX(id) FROM projects), 1));
SELECT setval('project_owners_id_seq', COALESCE((SELECT MAX(id) FROM project_owners), 1));
SELECT setval('project_hours_id_seq', COALESCE((SELECT MAX(id) FROM project_hours), 1));
SELECT setval('expenses_id_seq', COALESCE((SELECT MAX(id) FROM expenses), 1));
SELECT setval('taxes_id_seq', COALESCE((SELECT MAX(id) FROM taxes), 1));

SET session_replication_role = DEFAULT; -- reactiva FK checks

-- Export completo.